import { readFileSync, writeFileSync } from 'fs';
const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const repo = input.repo;
const labelFilter = input.labelFilter;
const token = process.env.GITHUB_TOKEN;
if (!repo) { writeFileSync('/output/result.json', JSON.stringify({ error: 'repo trigger param is required', options: [] })); process.exit(1); }
if (!token) { writeFileSync('/output/result.json', JSON.stringify({ error: 'GITHUB_TOKEN secret not set', options: [] })); process.exit(1); }
const url = new URL(`https://api.github.com/repos/${repo}/issues`);
url.searchParams.set('state', 'open');
url.searchParams.set('per_page', '100');
if (labelFilter) url.searchParams.set('labels', labelFilter);
const res = await fetch(url, { headers: { Authorization: `Bearer ${token}`, Accept: 'application/vnd.github+json' } });
if (!res.ok) { const body = await res.text(); writeFileSync('/output/result.json', JSON.stringify({ error: `GitHub ${res.status}: ${body}`, options: [] })); process.exit(1); }
const issues = await res.json();
const onlyIssues = issues.filter((i) => !i.pull_request);
const options = onlyIssues.map((i) => {
  const labels = (i.labels || []).map((l) => typeof l === 'string' ? l : l.name);
  return {
    id: String(i.number),
    label: `#${i.number} ${i.title}`,
    sublabel: labels.join(', '),
    href: i.html_url,
    badges: labels,
    currentAssignee: i.assignee?.login,
    raw: { issueNumber: i.number, title: i.title, body: i.body, labels, currentAssignee: i.assignee?.login, url: i.html_url },
  };
});
writeFileSync('/output/result.json', JSON.stringify({ options, repo, summary: `Fetched ${options.length} open issue(s) from ${repo}` }));

import { readFileSync, writeFileSync } from 'fs';
const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const assignments = input.assignments || [];
const repo = input.repo || input.steps?.['fetch-backlog']?.repo;
const token = process.env.GITHUB_TOKEN;
const apiKey = process.env.PLATFORM_API_KEY;
const baseUrl = process.env.APP_BASE_URL;
const humanAssignments = [];
const agentRuns = [];
const errors = [];
for (const a of assignments) {
  const issueNumber = a.raw?.issueNumber ?? Number(a.itemId);
  try {
    if (a.assigneeKind === 'human') {
      if (!repo || !token) { errors.push({ itemId: a.itemId, kind: 'human', message: 'repo or GITHUB_TOKEN missing' }); continue; }
      const res = await fetch(`https://api.github.com/repos/${repo}/issues/${issueNumber}`, {
        method: 'PATCH',
        headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json', Accept: 'application/vnd.github+json' },
        body: JSON.stringify({ assignees: [a.assigneeId], labels: [`priority/${a.priority}`] }),
      });
      if (!res.ok) { const body = await res.text(); errors.push({ itemId: a.itemId, kind: 'human', message: `GitHub PATCH ${res.status}: ${body}` }); }
      else { humanAssignments.push({ issueNumber, assignee: a.assigneeId, priority: a.priority }); }
    } else if (a.assigneeKind === 'agent') {
      if (!apiKey || !baseUrl) { errors.push({ itemId: a.itemId, kind: 'agent', message: 'PLATFORM_API_KEY or APP_BASE_URL missing' }); continue; }
      const res = await fetch(`${baseUrl}/api/processes`, {
        method: 'POST',
        headers: { 'X-Api-Key': apiKey, 'Content-Type': 'application/json' },
        body: JSON.stringify({ definitionName: a.assigneeId, triggerName: 'manual', triggeredBy: 'backlog-triage', payload: { issueNumber } }),
      });
      const body = res.headers.get('content-type')?.includes('json') ? await res.json() : { error: await res.text() };
      if (!res.ok) { errors.push({ itemId: a.itemId, kind: 'agent', message: `Mediforce POST ${res.status}: ${body.error || ''}` }); }
      else { agentRuns.push({ issueNumber, workflowId: a.assigneeId, runId: body.instanceId, url: `${baseUrl}/runs/${body.instanceId}` }); }
    }
  } catch (err) {
    errors.push({ itemId: a.itemId, kind: a.assigneeKind, message: String(err?.message ?? err) });
  }
}
writeFileSync('/output/result.json', JSON.stringify({ humanAssignments, agentRuns, errors, summary: `Dispatched ${humanAssignments.length} human(s), ${agentRuns.length} agent run(s), ${errors.length} error(s)` }));
